<?php
namespace Tests\Feature;use App\Domain\Wallet\GoldReasonCode;use App\Domain\Wallet\WalletService;use App\Models\Character;use App\Models\User;use Illuminate\Database\QueryException;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\DB;use Tests\TestCase;class WalletSchemaTest extends TestCase{use RefreshDatabase;public function test_ledger_restricts_character_deletion_and_no_triggers_exist(){$c=Character::factory()->for(User::factory())->create();app(WalletService::class)->credit($c,1,GoldReasonCode::ADMIN_GRANT);try{$c->delete();$this->fail();}catch(QueryException $e){$this->assertDatabaseHas('characters',['id'=>$c->id]);$this->assertDatabaseCount('gold_transactions',1);}$triggers=DB::select("SELECT TRIGGER_NAME FROM information_schema.TRIGGERS WHERE TRIGGER_SCHEMA=DATABASE() AND EVENT_OBJECT_TABLE IN ('character_wallets','gold_transactions')");$this->assertCount(0,$triggers);}}
